// --- constants / config ---------------------------------------------------
const OWNER = '{{GITHUB_OWNER}}';
const REPO = '{{GITHUB_REPO_NAME}}';
const BRANCH = 'main';
const MORGEN_LIST_URL = 'https://api.morgen.so/v3/tasks/list';
const MORGEN_LIST_COST = 10;              // rate budget points for the list call
const POINT_BUDGET_CEILING = 85;          // safety rail #29
const FLIP_RATIO_LIMIT = 0.5;             // safety rail #28
const FLIP_RATIO_MIN_SAMPLE = 4;          // Agent 7 floor fix
const COMMIT_PREFIX = '[bot:W2]';
const SYNC_STATE_PATH = '.sync-state.json';

// Top-level try/catch — never allow the workflow to throw
try {
  // --- 1. POLL MORGEN --------------------------------------------------------
  let morgenResp;
  try {
    morgenResp = await authedRequest('httpHeaderAuth',
      {
        method: 'GET',
        url: MORGEN_LIST_URL,
        json: true,
        returnFullResponse: false,
      },
    );
  } catch (httpErr) {
    const status = (httpErr && (httpErr.statusCode || httpErr.httpCode)) || null;
    // Rail #27 — auth failure, abort early
    if (status === 401 || status === 403) {
      return [{
        json: {
          error: { message: 'Morgen auth failed: ' + status, name: 'AuthError' },
          failed: true,
          rail: '#27',
          timestamp: new Date().toISOString(),
        },
      }];
    }
    throw httpErr;
  }

  // Rail #26a — malformed response shape
  if (!morgenResp || !morgenResp.data || !Array.isArray(morgenResp.data.tasks)) {
    return [{
      json: {
        error: { message: 'Malformed Morgen response: missing data.tasks[]', name: 'MalformedResponse' },
        failed: true,
        rail: '#26a',
        timestamp: new Date().toISOString(),
      },
    }];
  }

  const allTasks = morgenResp.data.tasks;

  // Filter to native Morgen tasks only (skip external integration mirrors)
  const morgenTasks = allTasks.filter((t) => {
    const iid = t && t.integrationId;
    return iid == null || iid === 'morgen';
  });

  // --- 2. LOAD .sync-state.json FROM GITHUB ----------------------------------
  let syncStateRaw = '';
  let syncStateSha = null;
  try {
    const stateResp = await authedRequest('githubApi',
      {
        method: 'GET',
        url: 'https://api.github.com/repos/' + OWNER + '/' + REPO + '/contents/' + SYNC_STATE_PATH + '?ref=' + BRANCH,
        json: true,
        headers: { 'Accept': 'application/vnd.github+json' },
      },
    );
    if (stateResp && stateResp.content) {
      syncStateRaw = Buffer.from(stateResp.content, 'base64').toString('utf8');
      syncStateSha = stateResp.sha || null;
    }
  } catch (stateErr) {
    const status = (stateErr && (stateErr.statusCode || stateErr.httpCode)) || null;
    if (status === 401 || status === 403) {
      return [{
        json: {
          error: { message: 'GitHub auth failed loading sync-state: ' + status, name: 'AuthError' },
          failed: true,
          rail: '#27',
          timestamp: new Date().toISOString(),
        },
      }];
    }
    if (status !== 404) throw stateErr;
  }

  const syncState = loadSyncState(syncStateRaw);

  // Count how many entries in mapping currently claim a morgenTaskId
  const trackedMorgenEntries = [];
  for (const h of Object.keys(syncState.entries || {})) {
    const e = syncState.entries[h];
    if (e && e.morgenTaskId) trackedMorgenEntries.push({ hash: h, entry: e });
  }
  const trackedCount = trackedMorgenEntries.length;

  // Rail #26b — Morgen returned zero tasks but mapping has tracked ones → outage
  if (morgenTasks.length === 0 && trackedCount > 0) {
    return [{
      json: {
        error: { message: 'Morgen returned 0 tasks but ' + trackedCount + ' mapping entries have morgenTaskId (suspected outage)', name: 'SuspectedOutage' },
        failed: true,
        rail: '#26b',
        timestamp: new Date().toISOString(),
      },
    }];
  }

  // Build quick lookup: morgenTaskId → morgenTask
  const morgenById = new Map();
  for (const mt of morgenTasks) {
    if (mt && mt.id) morgenById.set(String(mt.id), mt);
  }

  // Reverse _tagCache lookup: tagUUID → notionLabel
  const tagUuidToLabel = {};
  const tagCache = syncState._tagCache || {};
  for (const label of Object.keys(tagCache)) {
    const uuid = tagCache[label];
    if (uuid) tagUuidToLabel[String(uuid)] = label;
  }

  // --- 3. CLASSIFY CHANGES (4 DIRECTIONS) ------------------------------------
  const dirtyFiles = new Map(); // path → { contentPromise, newContent, lines }
  const opsLog = { done: 0, edit: 0, newTask: 0, softDelete: 0, skipped: 0 };
  const operations = []; // for audit

  // Helper: lazily fetch a source file from GitHub
  const fileCache = new Map(); // path → { content, sha, lines }
  async function fetchFile(path) {
    if (fileCache.has(path)) return fileCache.get(path);
    let resp;
    try {
      resp = await authedRequest('githubApi',
        {
          method: 'GET',
          url: 'https://api.github.com/repos/' + OWNER + '/' + REPO + '/contents/' + path + '?ref=' + BRANCH,
          json: true,
          headers: { 'Accept': 'application/vnd.github+json' },
        },
      );
    } catch (fetchErr) {
      const status = (fetchErr && (fetchErr.statusCode || fetchErr.httpCode)) || null;
      if (status === 404) {
        // New file — start with empty shell
        const empty = { content: '', sha: null, lines: [] };
        fileCache.set(path, empty);
        return empty;
      }
      throw fetchErr;
    }
    const content = resp && resp.content ? Buffer.from(resp.content, 'base64').toString('utf8') : '';
    const lines = content.replace(/\r\n/g, '\n').replace(/\r/g, '\n').split('\n');
    const rec = { content, sha: resp && resp.sha ? resp.sha : null, lines };
    fileCache.set(path, rec);
    return rec;
  }

  // Direction A + B + C: iterate tracked mapping entries
  for (const { hash, entry } of trackedMorgenEntries) {
    const mtid = String(entry.morgenTaskId);
    const morgenTask = morgenById.get(mtid);

    if (!morgenTask) {
      // Direction C — Soft-delete: task no longer exists in Morgen
      const srcPath = entry.sourceFile;
      if (!srcPath || !isSafePath(srcPath)) {
        opsLog.skipped++;
        operations.push({ kind: 'soft-delete', hash, skipped: 'unsafe-path', srcPath });
        continue;
      }
      const file = await fetchFile.call(this, srcPath);
      const lineIdx = (entry.lineNo || 1) - 1;
      const cur = file.lines[lineIdx];
      if (typeof cur !== 'string') {
        opsLog.skipped++;
        operations.push({ kind: 'soft-delete', hash, skipped: 'line-oor', srcPath });
        continue;
      }
      const m = cur.match(/^(\s*)([-*+])\s+\[([ xX\/\-!?*])\]/);
      if (!m || m[3] === 'x' || m[3] === 'X') {
        // Already done or not a task line — nothing to do
        opsLog.skipped++;
        operations.push({ kind: 'soft-delete', hash, skipped: 'already-done', srcPath });
        continue;
      }
      const flipped = flipTaskDone(cur);
      file.lines[lineIdx] = flipped;
      dirtyFiles.set(srcPath, true);
      opsLog.softDelete++;
      operations.push({ kind: 'soft-delete', hash, srcPath, lineNo: entry.lineNo });
      // Mark entry archived
      const nextState = upsertMappingEntry(syncState, hash, { archived: true });
      syncState.entries = nextState.entries;
      continue;
    }

    // We have the Morgen task — check for completion or edit
    const isCompleted = morgenTask.progress === 'completed';
    const srcPath = entry.sourceFile;

    if (!srcPath || !isSafePath(srcPath)) {
      opsLog.skipped++;
      operations.push({ kind: 'check', hash, skipped: 'unsafe-path', srcPath });
      continue;
    }

    const file = await fetchFile.call(this, srcPath);
    const lineIdx = (entry.lineNo || 1) - 1;
    const cur = file.lines[lineIdx];
    if (typeof cur !== 'string') {
      opsLog.skipped++;
      operations.push({ kind: 'check', hash, skipped: 'line-oor', srcPath });
      continue;
    }
    const lineMatch = cur.match(/^(\s*)([-*+])\s+\[([ xX\/\-!?*])\]/);
    if (!lineMatch) {
      opsLog.skipped++;
      operations.push({ kind: 'check', hash, skipped: 'not-task-line', srcPath });
      continue;
    }
    const alreadyDoneInSrc = lineMatch[3] === 'x' || lineMatch[3] === 'X';

    // Direction A — Completion
    if (isCompleted && !alreadyDoneInSrc) {
      const flipped = flipTaskDone(cur);
      file.lines[lineIdx] = flipped;
      dirtyFiles.set(srcPath, true);
      opsLog.done++;
      operations.push({ kind: 'done', hash, srcPath, lineNo: entry.lineNo });
      const nextState = upsertMappingEntry(syncState, hash, { archived: true });
      syncState.entries = nextState.entries;
      continue;
    }

    // Direction B — Edit detection via hash comparison
    // Build a "what Morgen thinks this task is" task object and compare hash
    const morgenTitle = (morgenTask.title != null ? String(morgenTask.title) : '').trim();
    const morgenPrioInt = (function () {
      const p = morgenTask.priority;
      const n = parseInt(p, 10);
      return Number.isFinite(n) ? n : 0;
    })();
    const morgenDue = morgenTask.due ? String(morgenTask.due).slice(0, 10) : null;

    const morgenView = {
      sourceFile: entry.sourceFile,
      text: morgenTitle,
      priority: morgenPrioInt,
      due: morgenDue,
      scheduled: entry.scheduled || null,
    };
    const morgenHash = computeTaskHash(morgenView);

    if (morgenHash !== entry.hash && !alreadyDoneInSrc && !isCompleted) {
      // Edit direction — reconstruct the line
      const newTask = {
        text: morgenTitle,
        priority: morgenPrioInt,
        due: morgenDue,
        scheduled: entry.scheduled || null,
        start: entry.start || null,
        recurrence: entry.recurrence || null,
        done: false,
      };
      const newLine = reconstructObsidianLine(newTask, cur);
      if (newLine !== cur) {
        file.lines[lineIdx] = newLine;
        dirtyFiles.set(srcPath, true);
        opsLog.edit++;
        operations.push({ kind: 'edit', hash, srcPath, lineNo: entry.lineNo, oldHash: entry.hash, newHash: morgenHash });
        const nextPatch = {
          text: morgenTitle,
          priority: morgenPrioInt,
          due: morgenDue,
          lineHash: computeLineHash(newLine),
        };
        const nextState = upsertMappingEntry(syncState, hash, nextPatch);
        syncState.entries = nextState.entries;
      }
    }
  }

  // Direction D — New Morgen-origin tasks (no matching mapping entry)
  const mappedMorgenIds = new Set();
  for (const h of Object.keys(syncState.entries || {})) {
    const e = syncState.entries[h];
    if (e && e.morgenTaskId) mappedMorgenIds.add(String(e.morgenTaskId));
  }

  for (const mt of morgenTasks) {
    if (!mt || !mt.id) continue;
    if (mappedMorgenIds.has(String(mt.id))) continue;
    if (mt.progress === 'completed') continue; // don't import already-completed tasks

    // Resolve area from first tag UUID
    let areaKey = 'GENERAL';
    if (Array.isArray(mt.tags) && mt.tags.length > 0) {
      const firstTagId = String(mt.tags[0]);
      const label = tagUuidToLabel[firstTagId];
      if (label) areaKey = notionLabelToAreaKey(label);
    }
    const targetPath = areaKeyToFile(areaKey);
    if (!isSafePath(targetPath)) {
      opsLog.skipped++;
      operations.push({ kind: 'new', morgenId: mt.id, skipped: 'unsafe-path', targetPath });
      continue;
    }

    const file = await fetchFile.call(this, targetPath);

    // Build a clean task object for reconstructObsidianLine
    const morgenTitle = (mt.title != null ? String(mt.title) : '').trim();
    if (!morgenTitle) {
      opsLog.skipped++;
      operations.push({ kind: 'new', morgenId: mt.id, skipped: 'empty-title' });
      continue;
    }
    const morgenPrioInt = (function () {
      const n = parseInt(mt.priority, 10);
      return Number.isFinite(n) ? n : 0;
    })();
    const morgenDue = mt.due ? String(mt.due).slice(0, 10) : null;

    const newTask = {
      text: morgenTitle,
      priority: morgenPrioInt,
      due: morgenDue,
      scheduled: null,
      done: false,
    };
    const newLine = reconstructObsidianLine(newTask, null);

    // Append to file (ensure trailing newline after append)
    let newLineNo;
    if (file.lines.length > 0 && file.lines[file.lines.length - 1] === '') {
      newLineNo = file.lines.length; // 1-based = index of the slot we overwrite + 1
      file.lines[file.lines.length - 1] = newLine;
      file.lines.push('');
    } else {
      file.lines.push(newLine);
      newLineNo = file.lines.length; // 1-based
      file.lines.push('');
    }
    dirtyFiles.set(targetPath, true);
    opsLog.newTask++;

    // Create mapping entry
    const entryHash = computeTaskHash({
      sourceFile: targetPath,
      text: morgenTitle,
      priority: morgenPrioInt,
      due: morgenDue,
      scheduled: null,
    });
    const patch = {
      sourceFile: targetPath,
      lineNo: newLineNo,
      lineHash: computeLineHash(newLine),
      text: morgenTitle,
      area: areaKey,
      priority: morgenPrioInt,
      due: morgenDue,
      scheduled: null,
      morgenTaskId: String(mt.id),
      notionPageId: null,
      archived: false,
    };
    const nextState = upsertMappingEntry(syncState, entryHash, patch);
    syncState.entries = nextState.entries;
    mappedMorgenIds.add(String(mt.id));
    operations.push({ kind: 'new', morgenId: mt.id, srcPath: targetPath, lineNo: newLineNo, hash: entryHash });
  }

  // --- 4. SAFETY RAIL #28 — FLIP RATIO GUARD ---------------------------------
  const flipCount = opsLog.done + opsLog.softDelete;
  if (trackedCount >= FLIP_RATIO_MIN_SAMPLE) {
    const ratio = flipCount / Math.max(trackedCount, 1);
    if (ratio > FLIP_RATIO_LIMIT) {
      return [{
        json: {
          error: {
            message: 'Flip ratio guard tripped: ' + flipCount + '/' + trackedCount + ' = ' + ratio.toFixed(3) + ' > ' + FLIP_RATIO_LIMIT,
            name: 'FlipRatioExceeded',
          },
          failed: true,
          rail: '#28',
          ops: opsLog,
          timestamp: new Date().toISOString(),
        },
      }];
    }
  }

  // --- 5. NOTHING TO DO? exit clean -----------------------------------------
  if (dirtyFiles.size === 0) {
    return [{
      json: {
        ok: true,
        noop: true,
        morgenTaskCount: morgenTasks.length,
        trackedCount,
        ops: opsLog,
        pointsConsumed: MORGEN_LIST_COST,
        timestamp: new Date().toISOString(),
      },
    }];
  }

  // Always rewrite .sync-state.json when any mutation happened
  const newSyncStateContent = serializeSyncState(syncState);

  // --- 6. COMMIT VIA GITHUB GIT DATA API ------------------------------------
  // Step 6.1 — get head ref
  const refResp = await authedRequest('githubApi',
    {
      method: 'GET',
      url: 'https://api.github.com/repos/' + OWNER + '/' + REPO + '/git/refs/heads/' + BRANCH,
      json: true,
      headers: { 'Accept': 'application/vnd.github+json' },
    },
  );
  const headSha = refResp && refResp.object && refResp.object.sha;
  if (!headSha) {
    return [{
      json: {
        error: { message: 'Could not resolve head sha for branch ' + BRANCH, name: 'GitRefError' },
        failed: true,
        timestamp: new Date().toISOString(),
      },
    }];
  }

  // Step 6.2 — get base commit (for base_tree)
  const headCommitResp = await authedRequest('githubApi',
    {
      method: 'GET',
      url: 'https://api.github.com/repos/' + OWNER + '/' + REPO + '/git/commits/' + headSha,
      json: true,
      headers: { 'Accept': 'application/vnd.github+json' },
    },
  );
  const baseTreeSha = headCommitResp && headCommitResp.tree && headCommitResp.tree.sha;
  if (!baseTreeSha) {
    return [{
      json: {
        error: { message: 'Could not resolve base tree sha', name: 'GitTreeError' },
        failed: true,
        timestamp: new Date().toISOString(),
      },
    }];
  }

  // Step 6.3 — create blobs for every dirty file + sync-state.json
  const treeItems = [];

  // Dirty task files
  for (const path of dirtyFiles.keys()) {
    if (!isSafePath(path)) {
      opsLog.skipped++;
      continue;
    }
    const file = fileCache.get(path);
    const newContent = file.lines.join('\n');
    const blobResp = await authedRequest('githubApi',
      {
        method: 'POST',
        url: 'https://api.github.com/repos/' + OWNER + '/' + REPO + '/git/blobs',
        json: true,
        headers: { 'Accept': 'application/vnd.github+json' },
        body: {
          content: Buffer.from(newContent, 'utf8').toString('base64'),
          encoding: 'base64',
        },
      },
    );
    if (!blobResp || !blobResp.sha) {
      return [{
        json: { error: { message: 'Blob create failed for ' + path, name: 'BlobError' }, failed: true, timestamp: new Date().toISOString() },
      }];
    }
    treeItems.push({
      path: '05-Tasks/' + path,
      mode: '100644',
      type: 'blob',
      sha: blobResp.sha,
    });
  }

  // sync-state.json blob
  const stateBlobResp = await authedRequest('githubApi',
    {
      method: 'POST',
      url: 'https://api.github.com/repos/' + OWNER + '/' + REPO + '/git/blobs',
      json: true,
      headers: { 'Accept': 'application/vnd.github+json' },
      body: {
        content: Buffer.from(newSyncStateContent, 'utf8').toString('base64'),
        encoding: 'base64',
      },
    },
  );
  if (!stateBlobResp || !stateBlobResp.sha) {
    return [{
      json: { error: { message: 'Blob create failed for sync-state', name: 'BlobError' }, failed: true, timestamp: new Date().toISOString() },
    }];
  }
  treeItems.push({
    path: SYNC_STATE_PATH,
    mode: '100644',
    type: 'blob',
    sha: stateBlobResp.sha,
  });

  // Step 6.4 — create new tree
  const treeResp = await authedRequest('githubApi',
    {
      method: 'POST',
      url: 'https://api.github.com/repos/' + OWNER + '/' + REPO + '/git/trees',
      json: true,
      headers: { 'Accept': 'application/vnd.github+json' },
      body: {
        base_tree: baseTreeSha,
        tree: treeItems,
      },
    },
  );
  if (!treeResp || !treeResp.sha) {
    return [{
      json: { error: { message: 'Tree create failed', name: 'TreeError' }, failed: true, timestamp: new Date().toISOString() },
    }];
  }

  // Step 6.5 — create commit
  const commitMsg = COMMIT_PREFIX + ' morgen-sync: ' + opsLog.done + ' done, ' + opsLog.edit + ' edit, ' + opsLog.newTask + ' new, ' + opsLog.softDelete + ' soft-delete';
  const commitResp = await authedRequest('githubApi',
    {
      method: 'POST',
      url: 'https://api.github.com/repos/' + OWNER + '/' + REPO + '/git/commits',
      json: true,
      headers: { 'Accept': 'application/vnd.github+json' },
      body: {
        message: commitMsg,
        tree: treeResp.sha,
        parents: [headSha],
      },
    },
  );
  if (!commitResp || !commitResp.sha) {
    return [{
      json: { error: { message: 'Commit create failed', name: 'CommitError' }, failed: true, timestamp: new Date().toISOString() },
    }];
  }

  // Step 6.6 — update ref
  const patchRefResp = await authedRequest('githubApi',
    {
      method: 'PATCH',
      url: 'https://api.github.com/repos/' + OWNER + '/' + REPO + '/git/refs/heads/' + BRANCH,
      json: true,
      headers: { 'Accept': 'application/vnd.github+json' },
      body: {
        sha: commitResp.sha,
        force: false,
      },
    },
  );

  // --- 7. RETURN SUMMARY -----------------------------------------------------
  return [{
    json: {
      ok: true,
      commitSha: commitResp.sha,
      commitMessage: commitMsg,
      ops: opsLog,
      operations,
      morgenTaskCount: morgenTasks.length,
      trackedCount,
      dirtyFileCount: dirtyFiles.size,
      pointsConsumed: MORGEN_LIST_COST,
      refPatched: !!patchRefResp,
      timestamp: new Date().toISOString(),
    },
  }];
} catch (e) {
  const safe = {
    message: String((e && e.message) || e),
    name: (e && e.name) || 'Error',
  };
  return [{
    json: {
      error: safe,
      failed: true,
      timestamp: new Date().toISOString(),
    },
  }];
}
